import React, { useState, useEffect } from 'react';
import axios from 'axios';

const History = () => {
  const [history, setHistory] = useState([]);
  const [filter, setFilter] = useState('');

  useEffect(() => {
    const fetchHistory = async () => {
      try {
        const res = await axios.get('/api/history', {
          headers: { Authorization: localStorage.getItem('token') },
        });
        setHistory(res.data);
      } catch (err) {
        alert('Error fetching history');
      }
    };
    fetchHistory();
  }, []);

  const filteredHistory = history.filter(route => !filter || route.status === filter);

  const exportToCSV = () => {
    const csv = filteredHistory.map(route => `${route.date},${route.origin},${route.destination},${route.distance},${route.cost}`).join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'history.csv';
    a.click();
  };

  return (
    <div className="history">
      <h2>Route History</h2>
      <select value={filter} onChange={(e) => setFilter(e.target.value)}>
        <option value="">All</option>
        <option value="concluído">Concluído</option>
        <option value="em andamento">Em Andamento</option>
      </select>
      <button onClick={exportToCSV}>Export to CSV</button>
      <table>
        <thead>
          <tr>
            <th>Date</th>
            <th>Origin</th>
            <th>Destination</th>
            <th>Distance</th>
            <th>Cost</th>
            <th>Status</th>
          </tr>
        </thead>
        <tbody>
          {filteredHistory.map(route => (
            <tr key={route._id}>
              <td>{new Date(route.date).toLocaleDateString()}</td>
              <td>{route.origin}</td>
              <td>{route.destination}</td>
              <td>{route.distance} km</td>
              <td>R$ {route.cost}</td>
              <td>{route.status}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default History;
